  1	import React, { FC, useState } from 'react';
  2	
  3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  4	import { ExpandableSection, FormGroup, ModalVariant } from '@patternfly/react-core';
  5	
  6	import TabModal from '../TabModal/TabModal';
  7	
  8	import SelectSysprep from './SelectSysprep';
  9	import Sysprep from './Sysprep';
 10	
 11	export const SysprepModal: FC<{
 12	  autoUnattend: string;
 13	  enableCreation?: boolean;
 14	  isOpen: boolean;
 15	  namespace: string;
 16	  onClose: () => void;
 17	  onSysprepCreation?: (unattended: string, autoUnattend: string) => Promise<void> | void;
 18	  onSysprepSelected?: (sysprepName: string) => Promise<void> | void;
 19	  shouldCreateConfigMap?: boolean;
 20	  sysprepSelected?: string;
 21	  unattend: string;
 22	}> = ({
 23	  autoUnattend: initialAutoUnattend,
 24	  enableCreation = true,
 25	  isOpen,
 26	  namespace,
 27	  onClose,
 28	  onSysprepCreation,
 29	  onSysprepSelected,
 30	  shouldCreateConfigMap = true,
 31	  sysprepSelected,
 32	  unattend: initialUnattend,
 33	}) => {
 34	  const { t } = useKubevirtTranslation();
 35	  const [autoUnattend, setAutoUnattend] = useState(initialAutoUnattend);
 36	  const [unattend, setUnattend] = useState(initialUnattend);
 37	  const [creationSectionOpen, setCreationSection] = useState(shouldCreateConfigMap);
 38	  const [selectedSysprepName, setSelectedSysprepName] = useState(sysprepSelected);
 39	
 40	  const submitHandler = async () => {
 41	    if (enableCreation && creationSectionOpen) {
 42	      return await onSysprepCreation(unattend, autoUnattend);
 43	    }
 44	
 45	    if (onSysprepSelected) await onSysprepSelected(selectedSysprepName);
 46	  };
 47	
 48	  if (!enableCreation) {
 49	    return (
 50	      <TabModal
 51	        headerText={t('Sysprep')}
 52	        isOpen={isOpen}
 53	        onClose={onClose}
 54	        onSubmit={() => submitHandler()}
 55	      >
 56	        <div className="kv-sysprep-modal">
 57	          <FormGroup fieldId="select-sysprep" label={t('Attach existing sysprep')}>
 58	            <SelectSysprep
 59	              namespace={namespace}
 60	              onSelectSysprep={setSelectedSysprepName}
 61	              selectedSysprepName={selectedSysprepName}
 62	            />
 63	          </FormGroup>
 64	        </div>
 65	      </TabModal>
 66	    );
 67	  }
 68	
 69	  return (
 70	    <TabModal
 71	      headerText={t('Sysprep')}
 72	      isOpen={isOpen}
 73	      modalVariant={ModalVariant.medium}
 74	      onClose={onClose}
 75	      onSubmit={() => submitHandler()}
 76	    >
 77	      <div className="kv-sysprep-modal">
 78	        <ExpandableSection
 79	          data-test-id="expandable-new-sysprep-section"
 80	          isExpanded={creationSectionOpen}
 81	          isIndented
 82	          onToggle={(_event, val) => setCreationSection(val)}
 83	          toggleText={t('Create new sysprep')}
 84	        >
 85	          <Sysprep
 86	            autoUnattend={autoUnattend}
 87	            onAutoUnattendChange={setAutoUnattend}
 88	            onUnattendChange={setUnattend}
 89	            unattend={unattend}
 90	          />
 91	        </ExpandableSection>
 92	        <ExpandableSection
 93	          data-test-id="expandable-new-sysprep-section"
 94	          isExpanded={!creationSectionOpen}
 95	          isIndented
 96	          onToggle={() => setCreationSection(!creationSectionOpen)}
 97	          toggleText={t('Attach existing sysprep')}
 98	        >
 99	          <SelectSysprep
100	            namespace={namespace}
101	            onSelectSysprep={setSelectedSysprepName}
102	            selectedSysprepName={selectedSysprepName}
103	          />
104	        </ExpandableSection>
105	      </div>
106	    </TabModal>
107	  );
108	};

